<script setup lang="ts">
import { computed, ref, watch } from 'vue'; import type { ChannelSnapshot, MetricItem } from '@ct/shared'; import { dashboard } from '../api'; import { useFiltersStore } from '../stores/filters'; import { useAsyncData } from '../composables/useAsyncData'; import { useAutoRefresh } from '../composables/useAutoRefresh'; import AppShell from '../components/AppShell.vue'; import AsyncPanel from '../components/AsyncPanel.vue'; import DimensionWorkspace from '../components/DimensionWorkspace.vue'; import MetricMini from '../components/MetricMini.vue'; import RateBar from '../components/RateBar.vue'; import StatusTag from '../components/StatusTag.vue'; import HoursSelect from '../components/HoursSelect.vue'; import ChannelOperations from '../components/ChannelOperations.vue'
const props=defineProps<{ kind:'customers'|'channels'|'models' }>(); const filters=useFiltersStore(); const selectedKey=ref(''); const hours=ref(1); const history=ref<MetricItem[]>([]); const snapshots=ref<ChannelSnapshot[]>([]); const dimensionType=computed(()=>props.kind==='customers'?'instance_user':props.kind==='channels'?'instance_channel':'instance_model'); const title=computed(()=>({customers:'客户监控',channels:'渠道监控',models:'模型监控'}[props.kind]));
const state=useAsyncData(async()=>{const [metrics,channelData]=await Promise.all([dashboard.metrics({window:'1m',latest:true,dimension_type:dimensionType.value}),props.kind==='channels'?dashboard.channelSnapshots({instance_id:filters.instance_id||undefined,latest_only:true,limit:500}):Promise.resolve({items:[] as ChannelSnapshot[]})]); snapshots.value=channelData.items; const items=metrics.items.filter(x=>!filters.instance_id||x.instance_id===filters.instance_id); if(!items.some(x=>x.dimension_key===selectedKey.value)) selectedKey.value=items[0]?.dimension_key||''; await loadHistory(); return items}); const selected=computed(()=>state.data.value?.find(x=>x.dimension_key===selectedKey.value)); const snapshot=computed(()=>{const id=Number(selectedKey.value.split(':').pop()); return snapshots.value.find(x=>x.channel_id===id&&(!filters.instance_id||x.instance_id===filters.instance_id))}); const models=computed(()=>snapshot.value?.models_text.split(',').map(x=>x.trim()).filter(Boolean)||[])
async function loadHistory(){if(!selectedKey.value){history.value=[];return} history.value=(await dashboard.metricHistory({window:'1m',dimension_type:dimensionType.value,dimension_key:selectedKey.value,hours:hours.value})).items} watch(()=>[props.kind,filters.instance_id],()=>void state.reload()); watch([selectedKey,hours],()=>void loadHistory()); useAutoRefresh(state.reload)
const fmt=(v:number|null|undefined,s='')=>v==null?'—':`${v.toFixed(2)}${s}`
</script>
<template><AppShell :title="title"><AsyncPanel :loading="state.loading.value" :error="state.error.value" :empty="!state.data.value?.length" @retry="state.reload"><DimensionWorkspace v-if="state.data.value" v-model:selected-key="selectedKey" :items="state.data.value"><template #row="{item}"><div class="dimension-row"><strong>{{ item.display_key }}</strong><span>{{ item.request_count }} 请求 · {{ fmt(item.success_rate ? item.success_rate*100 : item.success_rate,'%') }}</span><RateBar :value="item.error_rate" tone="danger"/></div></template><template #detail><div v-if="selected" class="dimension-content"><div class="panel-title"><div><h2>{{ snapshot ? `${snapshot.channel_name} (#${snapshot.channel_id})` : selected.display_key }}</h2><StatusTag v-if="snapshot" :value="snapshot.status"/> <span v-if="snapshot">权重 {{ snapshot.weight }}</span></div><HoursSelect v-model="hours"/></div><div v-if="models.length" class="chips"><el-tag v-for="m in models.slice(0,4)" :key="m" type="info">{{m}}</el-tag><el-tag v-if="models.length>4">+{{models.length-4}}</el-tag></div><div class="mini-grid"><MetricMini label="请求数" :value="selected.request_count"/><MetricMini label="成功率" :value="fmt(selected.success_rate ? selected.success_rate*100 : selected.success_rate,'%')"/><MetricMini label="错误率" :value="fmt(selected.error_rate ? selected.error_rate*100 : selected.error_rate,'%')"/><MetricMini label="P50 / P95 / P99" :value="`${fmt(selected.p50_use_time,'s')} / ${fmt(selected.p95_use_time,'s')} / ${fmt(selected.p99_use_time,'s')}`"/><MetricMini label="Token In / Out" :value="`${selected.prompt_tokens} / ${selected.completion_tokens}`"/><MetricMini label="Quota" :value="selected.quota"/></div><div class="quality-bars"><RateBar :value="selected.success_rate" tone="success"/><RateBar :value="selected.error_rate" tone="danger"/><RateBar :value="selected.stream_rate"/><RateBar :value="selected.cache_token_rate"/></div><section class="trend-table"><h3>历史趋势</h3><el-table :data="history" height="250"><el-table-column prop="bucket_time" label="时间"><template #default="s">{{new Date(s.row.bucket_time).toLocaleString()}}</template></el-table-column><el-table-column prop="request_count" label="请求"/><el-table-column prop="error_count" label="错误"/><el-table-column prop="tpm" label="TPM"/><el-table-column prop="p95_use_time" label="P95"/></el-table></section><ChannelOperations v-if="kind==='channels'" :channel-id="Number(selectedKey.split(':').pop())"/></div></template></DimensionWorkspace></AsyncPanel></AppShell></template>
